// ── Helpers ───────────────────────────────────────────────────────────────────
// Points: 1 pt per full hour, 0.5 pt per 30 min, +5 bonus if 6+ hours
function calcPoints(hrs){
  if(!hrs||hrs<=0) return 0;
  const base = Math.round(hrs * 2) / 2;  // 0.5 increments (1hr=1, 30min=0.5)
  const bonus = hrs >= 6 ? 5 : 0;        // +5 if 6 or more hours
  return base + bonus;
}
const pad = n => String(n).padStart(2,"0");
function nowLocal(){ const d=new Date(); return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`; }
function todayDate(){ const d=new Date(); return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`; }
function fmtDate(s){ if(!s) return ""; const [y,m,day]=s.split("-"); const mo=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]; return `${mo[parseInt(m)-1]} ${parseInt(day)}, ${y}`; }
function fmtTime(s){ if(!s) return ""; return new Date(s).toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"}); }
function fmtMoney(val,sign=false){ const n=parseFloat(val); if(isNaN(n)) return "—"; const abs="$"+Math.abs(n).toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g,","); if(sign) return (n>=0?"+":"-")+abs; return (n<0?"-":"")+abs; }
function pColor(v){ const n=parseFloat(v); if(isNaN(n)) return C.textSecondary; return n>0?C.win:n<0?C.loss:C.textSecondary; }
function roundHalfUp(h){ return Math.ceil(h*2)/2; }  // round up to nearest 0.5hr
function calcHours(a,b){
  if(!a||!b) return null;
  let start = new Date(a);
  let end   = new Date(b);
  // If end is earlier than start (crossed midnight), add one day to end
  if(end <= start) end = new Date(end.getTime() + 24*3600000);
  const h = (end - start) / 3600000;
  return h > 0 ? roundHalfUp(h) : null;
}
function fmtH(h){ if(!h||h===0) return "—"; const hr=Math.floor(h),mn=Math.round((h-hr)*60); return mn>0?`${hr}h ${mn}m`:`${hr}h`; }
function mKey(d){ return d?d.slice(0,7):""; }
function mLabel(k){ if(!k) return ""; const [y,m]=k.split("-"); return new Date(parseInt(y),parseInt(m)-1,1).toLocaleString("default",{month:"long",year:"numeric"}); }
function uid(){ return Math.random().toString(36).slice(2,9); }
function fmtPhone(p){ const d=p.replace(/\D/g,""); if(d.length===10) return `(${d.slice(0,3)}) ${d.slice(3,6)}-${d.slice(6)}`; return p; }

