const SK = "bluffhouse_v6";
function load(){
  try{ const r=localStorage.getItem(SK); if(r) return JSON.parse(r); } catch(_){}
  return {games:[], players:[]};
}
function save(d){ try{ localStorage.setItem(SK,JSON.stringify(d)); } catch(_){} }

