// ── Shared backend (Netlify Blobs, passcode-gated) ─────────────────────────────
const API = "/api/state";
const PASS_KEY = "bluffhouse_pass";
async function apiGet(pass){
  const r = await fetch(API,{headers:{"x-room-pass":pass}});
  if(!r.ok){ const e=new Error("get failed"); e.code=r.status; throw e; }
  return r.json();
}
async function apiPost(pass,data){
  const r = await fetch(API,{method:"POST",headers:{"x-room-pass":pass,"content-type":"application/json"},body:JSON.stringify({data})});
  if(!r.ok){ const e=new Error("post failed"); e.code=r.status; throw e; }
  return r.json();
}

